     */
    error CreatePolicy_InvalidSafeOwner(address unauthorizedOwner, address safe);

    /**
     * @dev Thrown when an unauthorized address signs a create policy payloads.
     */
    error CreatePolicy_UnauthorizedCreatePolicySigner();

